import datetime
from dataclasses import dataclass
from enum import Enum
from typing import Dict, List

class ReportPeriod(Enum):
    MONTH = 1
    QUARTER = 2
    YEAR = 3

@dataclass
class Transaction:
    date: datetime.date
    amount: float
    description: str

class AccountingReport:
    def __init__(self, transactions: List[Transaction], period: ReportPeriod):
        self.transactions = transactions
        self.period = period

    def generate_report(self) -> Dict[str, float]:
        report = {}
        if self.period == ReportPeriod.MONTH:
            report = self.generate_monthly_report()
        elif self.period == ReportPeriod.QUARTER:
            report = self.generate_quarterly_report()
        elif self.period == ReportPeriod.YEAR:
            report = self.generate_yearly_report()
        return report

    def generate_monthly_report(self) -> Dict[str, float]:
        report = {}
        current_month = datetime.date.today().month
        current_year = datetime.date.today().year
        total_revenue = 0
        total_expenses = 0
        for transaction in self.transactions:
            if transaction.date.month == current_month and transaction.date.year == current_year:
                if transaction.amount > 0:
                    total_revenue += transaction.amount
                else:
                    total_expenses += abs(transaction.amount)
        report['total_revenue'] = total_revenue
        report['total_expenses'] = total_expenses
        report['net_profit'] = total_revenue - total_expenses
        return report

    def generate_quarterly_report(self) -> Dict[str, float]:
        report = {}
        current_quarter = (datetime.date.today().month - 1) // 3 + 1
        current_year = datetime.date.today().year
        total_revenue = 0
        total_expenses = 0
        for transaction in self.transactions:
            if (transaction.date.month - 1) // 3 + 1 == current_quarter and transaction.date.year == current_year:
                if transaction.amount > 0:
                    total_revenue += transaction.amount
                else:
                    total_expenses += abs(transaction.amount)
        report['total_revenue'] = total_revenue
        report['total_expenses'] = total_expenses
        report['net_profit'] = total_revenue - total_expenses
        return report

    def generate_yearly_report(self) -> Dict[str, float]:
        report = {}
        current_year = datetime.date.today().year
        total_revenue = 0
        total_expenses = 0
        for transaction in self.transactions:
            if transaction.date.year == current_year:
                if transaction.amount > 0:
                    total_revenue += transaction.amount
                else:
                    total_expenses += abs(transaction.amount)
        report['total_revenue'] = total_revenue
        report['total_expenses'] = total_expenses
        report['net_profit'] = total_revenue - total_expenses
        return report

def main():
    transactions = [
        Transaction(datetime.date(2024, 9, 1), 1000, 'Sale'),
        Transaction(datetime.date(2024, 9, 5), -500, 'Expense'),
        Transaction(datetime.date(2024, 9, 10), 2000, 'Sale'),
        Transaction(datetime.date(2024, 9, 15), -1000, 'Expense'),
    ]
    report = AccountingReport(transactions, ReportPeriod.MONTH)
    print(report.generate_report())

if __name__ == '__main__':
    main()

import datetime
from enum import Enum
from dataclasses import dataclass
from typing import Dict, List

class ReportType(Enum):
    MONTHLY = 1
    QUARTERLY = 2
    YEARLY = 3

@dataclass
class Transaction:
    date: datetime.date
    amount: float
    description: str

class AccountingSystem:
    def __init__(self, data: List[Transaction]):
        self.data = data

    def get_transactions(self, start_date: datetime.date, end_date: datetime.date) -> List[Transaction]:
        return [t for t in self.data if start_date <= t.date <= end_date]

class ReportGenerator:
    def __init__(self, accounting_system: AccountingSystem):
        self.accounting_system = accounting_system

    def generate_report(self, report_type: ReportType, start_date: datetime.date, end_date: datetime.date) -> Dict[str, float]:
        transactions = self.accounting_system.get_transactions(start_date, end_date)
        total_revenue = sum(t.amount for t in transactions if t.amount > 0)
        total_expenses = sum(abs(t.amount) for t in transactions if t.amount < 0)
        report = {
            'start_date': start_date,
            'end_date': end_date,
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'net_profit': total_revenue - total_expenses
        }
        return report

    def generate_monthly_report(self, year: int, month: int) -> Dict[str, float]:
        start_date = datetime.date(year, month, 1)
        if month == 12:
            end_date = datetime.date(year, month, 31)
        else:
            end_date = datetime.date(year, month + 1, 1) - datetime.timedelta(days=1)
        return self.generate_report(ReportType.MONTHLY, start_date, end_date)

    def generate_quarterly_report(self, year: int, quarter: int) -> Dict[str, float]:
        if quarter == 1:
            start_date = datetime.date(year, 1, 1)
            end_date = datetime.date(year, 3, 31)
        elif quarter == 2:
            start_date = datetime.date(year, 4, 1)
            end_date = datetime.date(year, 6, 30)
        elif quarter == 3:
            start_date = datetime.date(year, 7, 1)
            end_date = datetime.date(year, 9, 30)
        else:
            start_date = datetime.date(year, 10, 1)
            end_date = datetime.date(year, 12, 31)
        return self.generate_report(ReportType.QUARTERLY, start_date, end_date)

    def generate_yearly_report(self, year: int) -> Dict[str, float]:
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        return self.generate_report(ReportType.YEARLY, start_date, end_date)

