import datetime
from dataclasses import dataclass
from enum import Enum
from typing import List

class ReportType(Enum):
    MONTHLY = 1
    QUARTERLY = 2
    YEARLY = 3

@dataclass
class Transaction:
    date: datetime.date
    amount: float
    description: str

class AccountingSystem:
    def __init__(self, data):
        self.data = data

    def get_transactions(self, start_date: datetime.date, end_date: datetime.date) -> List[Transaction]:
        return [t for t in self.data if start_date <= t.date <= end_date]

class ReportGenerator:
    def __init__(self, accounting_system: AccountingSystem):
        self.accounting_system = accounting_system

    def generate_report(self, report_type: ReportType, year: int) -> str:
        if report_type == ReportType.MONTHLY:
            return self.generate_monthly_report(year)
        elif report_type == ReportType.QUARTERLY:
            return self.generate_quarterly_report(year)
        elif report_type == ReportType.YEARLY:
            return self.generate_yearly_report(year)

    def generate_monthly_report(self, year: int) -> str:
        report = ""
        for month in range(1, 13):
            start_date = datetime.date(year, month, 1)
            if month == 12:
                end_date = datetime.date(year, month, 31)
            else:
                end_date = datetime.date(year, month + 1, 1) - datetime.timedelta(days=1)
            transactions = self.accounting_system.get_transactions(start_date, end_date)
            total_amount = sum(t.amount for t in transactions)
            report += f"Month {month}: {total_amount}\n"
        return report

    def generate_quarterly_report(self, year: int) -> str:
        report = ""
        for quarter in range(1, 5):
            if quarter == 1:
                start_date = datetime.date(year, 1, 1)
                end_date = datetime.date(year, 3, 31)
            elif quarter == 2:
                start_date = datetime.date(year, 4, 1)
                end_date = datetime.date(year, 6, 30)
            elif quarter == 3:
                start_date = datetime.date(year, 7, 1)
                end_date = datetime.date(year, 9, 30)
            elif quarter == 4:
                start_date = datetime.date(year, 10, 1)
                end_date = datetime.date(year, 12, 31)
            transactions = self.accounting_system.get_transactions(start_date, end_date)
            total_amount = sum(t.amount for t in transactions)
            report += f"Quarter {quarter}: {total_amount}\n"
        return report

    def generate_yearly_report(self, year: int) -> str:
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        transactions = self.accounting_system.get_transactions(start_date, end_date)
        total_amount = sum(t.amount for t in transactions)
        return f"Year {year}: {total_amount}"

