import datetime
import pandas as pd

class AccountingReport:
    def __init__(self, data, start_date, end_date):
        self.data = data
        self.start_date = start_date
        self.end_date = end_date

    def generate_report(self):
        report_data = self.data[(self.data['date'] >= self.start_date) & (self.data['date'] <= self.end_date)]
        return report_data

    def get_total_revenue(self):
        return self.generate_report()['revenue'].sum()

    def get_total_expenses(self):
        return self.generate_report()['expenses'].sum()

    def get_net_profit(self):
        return self.get_total_revenue() - self.get_total_expenses()

class QuarterlyReport(AccountingReport):
    def __init__(self, data, year, quarter):
        start_date = datetime.date(year, (quarter-1)*3+1, 1)
        end_date = datetime.date(year, quarter*3, 1)
        if quarter == 4:
            end_date = datetime.date(year, 12, 31)
        super().__init__(data, start_date, end_date)

class MonthlyReport(AccountingReport):
    def __init__(self, data, year, month):
        start_date = datetime.date(year, month, 1)
        if month == 12:
            end_date = datetime.date(year, month, 31)
        else:
            end_date = datetime.date(year, month+1, 1)
        end_date = end_date - datetime.timedelta(days=1)
        super().__init__(data, start_date, end_date)

class YearlyReport(AccountingReport):
    def __init__(self, data, year):
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        super().__init__(data, start_date, end_date)

