    def add_transaction(self, transaction: Transaction):
        self.transactions.append(transaction)

    def get_transactions(self, start_date: datetime.date, end_date: datetime.date):
        return [transaction for transaction in self.transactions if transaction.date >= start_date and transaction.date <= end_date]

def generate_accounting_report(report_period: ReportPeriod, start_date: datetime.date, end_date: datetime.date, accounting_system: AccountingSystem):
