        asset_summary = {}
        for date, transactions in self.data.items():
            if self.start_date <= date <= self.end_date:
                for transaction in transactions:
                    if transaction['account_type'] == 'asset':
                        asset_summary[transaction['account_name']] = asset_summary.get(transaction['account_name'], 0) + transaction['amount']
