@dataclass
class Transaction:
    date: datetime.date
    description: str
    debit: float
    credit: float

class AccountingReport:
    def __init__(self, transactions):
        self.transactions = transactions

    def generate_report(self, start_date, end_date):
        report = []
        for transaction in self.transactions:
            if start_date <= transaction.date <= end_date:
                report.append(transaction)
        return report

    def get_total_debit(self, report):
        return sum(transaction.debit for transaction in report)

    def get_total_credit(self, report):
        return sum(transaction.credit for transaction in report)

    def get_net_profit(self, report):
        return self.get_total_credit(report) - self.get_total_debit(report)

def generate_monthly_report(transactions, year, month):
    start_date = datetime.date(year, month, 1)
    if month == 12:
        end_date = datetime.date(year, month, 31)
    else:
        end_date = datetime.date(year, month + 1, 1) - datetime.timedelta(days=1)
    report = AccountingReport(transactions)
    return report.generate_report(start_date, end_date)

def generate_quarterly_report(transactions, year, quarter):
    if quarter == 1:
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 3, 31)
    elif quarter == 2:
        start_date = datetime.date(year, 4, 1)
        end_date = datetime.date(year, 6, 30)
    elif quarter == 3:
        start_date = datetime.date(year, 7, 1)
        end_date = datetime.date(year, 9, 30)
    else:
        start_date = datetime.date(year, 10, 1)
        end_date = datetime.date(year, 12, 31)
    report = AccountingReport(transactions)
    return report.generate_report(start_date, end_date)

def generate_yearly_report(transactions, year):
    start_date = datetime.date(year, 1, 1)
    end_date = datetime.date(year, 12, 31)
    report = AccountingReport(transactions)
    return report.generate_report(start_date, end_date)

