class AccountingSystem:
    def __init__(self, company_name, start_date, end_date):
        self.company_name = company_name
        self.start_date = start_date
        self.end_date = end_date
        self.transactions = []

    def add_transaction(self, date, description, amount):
        self.transactions.append({"date": date, "description": description, "amount": amount})

    def generate_report(self, period):
        if period == "monthly":
            start_date = self.start_date.replace(day=1)
            end_date = self.end_date
        elif period == "quarterly":
            start_date = self.start_date.replace(day=1, month=(self.start_date.month - (self.start_date.month - 1) % 3 + 1))
            end_date = self.end_date
        elif period == "yearly":
            start_date = self.start_date.replace(day=1, month=1)
            end_date = self.end_date
        else:
            raise ValueError("Invalid period")

        report = []
        for transaction in self.transactions:
            if start_date <= transaction["date"] <= end_date:
                report.append(transaction)

        return report

    def print_report(self, report):
        print("Report for", self.company_name)
        print("Period:", self.start_date, "to", self.end_date)
        print("Transactions:")
        for transaction in report:
            print(transaction["date"], transaction["description"], transaction["amount"])

    def export_report(self, report, filename):
        with open(filename, "w") as f:
            f.write("Report for " + self.company_name + "\n")
            f.write("Period: " + str(self.start_date) + " to " + str(self.end_date) + "\n")
            f.write("Transactions:\n")
            for transaction in report:
                f.write(str(transaction["date"]) + " " + transaction["description"] + " " + str(transaction["amount"]) + "\n")

