def print_sequence(sequence):
    for i in range(len(sequence)):
        print(f"Term {i+1}: {sequence[i]}")

def fibonacci(n):
    sequence = [0, 1]
    while len(sequence) < n:
        sequence.append(sequence[-1] + sequence[-2])
    return sequence

def factorial(n):
    sequence = [1]
    for i in range(1, n):
        sequence.append(sequence[-1] * (i+1))
    return sequence

def geometric_progression(a, r, n):
    sequence = [a]
    for i in range(1, n):
        sequence.append(sequence[-1] * r)
    return sequence

