import random

class Card:
    def __init__(self, suit, value):
        self.suit = suit
        self.value = value

    def __repr__(self):
        return f"{self.value} of {self.suit}"

class Deck:
    def __init__(self):
        self.cards = []
        self.suits = ['Hearts', 'Diamonds', 'Clubs', 'Spades']
        self.values = ['2', '3', '4', '5', '6', '7', '8', '9', '10', 'Jack', 'Queen', 'King', 'Ace']

        for suit in self.suits:
            for value in self.values:
                self.cards.append(Card(suit, value))

    def shuffle(self):
        random.shuffle(self.cards)

    def deal(self):
        return self.cards.pop()

class Hand:
    def __init__(self):
        self.cards = []

    def add_card(self, card):
        self.cards.append(card)

    def get_value(self):
        value = 0
        aces = 0
        for card in self.cards:
            if card.value.isnumeric():
                value += int(card.value)
            else:
                if card.value == 'Ace':
                    aces += 1
                    value += 11
                else:
                    value += 10

        while value > 21 and aces:
            value -= 10
            aces -= 1

        return value

    def __repr__(self):
        return f"Hand value: {self.get_value()} with cards {self.cards}"

def play_game():
    deck = Deck()
    deck.shuffle()

    player_hand = Hand()
    dealer_hand = Hand()

    for _ in range(2):
        player_hand.add_card(deck.deal())
        dealer_hand.add_card(deck.deal())

    print("Your hand is:", player_hand)
    print("Dealer's up card is:", dealer_hand.cards[0])

    while True:
        action = input("Do you want to hit or stay? ")
        if action.lower() == "hit":
            player_hand.add_card(deck.deal())
            print("Your hand is:", player_hand)
            if player_hand.get_value() > 21:
                print("You busted! Dealer wins.")
                return
        elif action.lower() == "stay":
            break
        else:
            print("Invalid input. Please enter 'hit' or 'stay'.")

    print("Dealer's hand is:", dealer_hand)

    while dealer_hand.get_value() < 17:
        dealer_hand.add_card(deck.deal())
        print("Dealer's hand is:", dealer_hand)

    if dealer_hand.get_value() > 21:
        print("Dealer busted! You win.")
    elif dealer_hand.get_value() < player_hand.get_value():
        print("Your score is higher. You win.")
    elif dealer_hand.get_value() > player_hand.get_value():
        print("Dealer's score is higher. Dealer wins.")
    else:
        print("It's a tie.")

play_game()

