class CodeMask:
    def __init__(self):
        self.keywords = ['class', 'def', 'for', 'while', 'if', 'else', 'elif']
        self.variables = ['x', 'y', 'z', 'a', 'b', 'c']
        self.functions = ['print', 'input', 'len', 'max', 'min', 'sum']

    def mask_code(self, code):
        lines = code.split('\n')
        masked_lines = []
        for line in lines:
            words = line.split()
            masked_words = []
            for word in words:
                if word in self.keywords:
                    masked_words.append(word)
                elif word in self.functions:
                    masked_words.append(word)
                elif word.isalpha():
                    masked_words.append(random.choice(self.variables))
                else:
                    masked_words.append(word)
            masked_lines.append(' '.join(masked_words))
        return '\n'.join(masked_lines)

